import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        int nodeCount = (int) n;
        int edgeCount = edges.length;
        List<int[]>[] normalOutEdges = new List[nodeCount];
        List<int[]>[] reverseCandidates = new List[nodeCount];

        for (int i = 0; i < nodeCount; i++) {
            normalOutEdges[i] = new ArrayList<>();
            reverseCandidates[i] = new ArrayList<>();
        }

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int w = (int) edge[2];
            normalOutEdges[u].add(new int[]{v, w});
            reverseCandidates[v].add(new int[]{u, w});
        }

        long[][] dist = new long[nodeCount][2];
        for (int i = 0; i < nodeCount; i++) {
            dist[i][0] = Long.MAX_VALUE;
            dist[i][1] = Long.MAX_VALUE;
        }
        dist[0][0] = 0;

        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.add(new long[]{0, 0, 0});

        while (!pq.isEmpty()) {
            long[] curr = pq.poll();
            long cost = curr[0];
            int u = (int) curr[1];
            int state = (int) curr[2];

            if (cost > dist[u][state]) 
                continue;

            if (state == 0) {
                for (int[] edge : normalOutEdges[u]) {
                    int v = edge[0];
                    int w = edge[1];
                    long ncost = cost + w;
                    if (ncost < dist[v][0]) {
                        dist[v][0] = ncost;
                        pq.add(new long[]{ncost, v, 0});
                    }
                }

                for (int[] edge : reverseCandidates[u]) {
                    int v = edge[0];
                    int w = edge[1];
                    long ncost = cost + 2L * w;
                    if (ncost < dist[v][0]) {
                        dist[v][0] = ncost;
                        pq.add(new long[]{ncost, v, 0});
                    }
                }
            }

            for (int[] edge : normalOutEdges[u]) {
                int v = edge[0];
                int w = edge[1];
                long ncost = cost + w;
                if (ncost < dist[v][state]) {
                    dist[v][state] = ncost;
                    pq.add(new long[]{ncost, v, state});
                }
            }
        }

        long ans = Math.min(dist[nodeCount-1][0], dist[nodeCount-1][1]);
        return ans == Long.MAX_VALUE ? -1 : ans;
    }
}
```

