import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        int numNodes = (int) n;
        List<int[]>[] inEdges = new ArrayList[numNodes];
        List<int[]>[] outEdges = new ArrayList[numNodes];
        for (int i = 0; i < numNodes; i++) {
            inEdges[i] = new ArrayList<>();
            outEdges[i] = new ArrayList<>();
        }

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int w = (int) edge[2];
            outEdges[u].add(new int[]{v, w});
            inEdges[v].add(new int[]{u, w});
        }

        long[] dist0 = new long[numNodes];
        long[] dist1 = new long[numNodes];
        Arrays.fill(dist0, Long.MAX_VALUE);
        Arrays.fill(dist1, Long.MAX_VALUE);
        dist0[0] = 0;

        boolean[] used = new boolean[numNodes];

        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
        pq.offer(new long[]{0, 0, 0});

        while (!pq.isEmpty()) {
            long[] top = pq.poll();
            long cost = top[0];
            int node = (int) top[1];
            int layer = (int) top[2];

            if (layer == 0) {
                if (used[node]) 
                    continue;
                used[node] = true;

                for (int[] inEdge : inEdges[node]) {
                    int next = inEdge[0];
                    int weight = inEdge[1];
                    long newCost = cost + 2L * weight;
                    if (!used[next]) {
                        if (newCost < dist0[next]) {
                            dist0[next] = newCost;
                            pq.offer(new long[]{newCost, next, 0});
                        }
                    } else {
                        if (newCost < dist1[next]) {
                            dist1[next] = newCost;
                            pq.offer(new long[]{newCost, next, 1});
                        }
                    }
                }

                for (int[] outEdge : outEdges[node]) {
                    int next = outEdge[0];
                    int weight = outEdge[1];
                    long newCost = cost + weight;
                    if (!used[next]) {
                        if (newCost < dist0[next]) {
                            dist0[next] = newCost;
                            pq.offer(new long[]{newCost, next, 0});
                        }
                    } else {
                        if (newCost < dist1[next]) {
                            dist1[next] = newCost;
                            pq.offer(new long[]{newCost, next, 1});
                        }
                    }
                }
            } else {
                for (int[] outEdge : outEdges[node]) {
                    int next = outEdge[0];
                    int weight = outEdge[1];
                    long newCost = cost + weight;
                    if (!used[next]) {
                        if (newCost < dist0[next]) {
                            dist0[next] = newCost;
                            pq.offer(new long[]{newCost, next, 0});
