                        if (newCost < dist1[next]) {
                            dist1[next] = newCost;
                            pq.offer(new long[]{newCost, next, 1});
                        }
                    }
                }
            }
        }

        long ans = Math.min(dist0[numNodes-1], dist1[numNodes-1]);
        return ans == Long.MAX_VALUE ? -1 : ans;
    }
}
